"""
Rosalind Problem 3: Complementing a Strand of DNA
https://rosalind.info/problems/revc/

Given a DNA string, return its reverse complement:
1. Complement each base (A<->T, G<->C)
2. Reverse the resulting string
"""

dna = ""

tablo = str.maketrans("ATGC", "TACG")
komplement = dna.translate(tablo)
print(komplement[::-1])
